import java.util.Scanner;public class SwitchCaseJava {    public static void main(String[] args) {        Scanner inputSexo = new Scanner(System.in);        System.out.println("Qual seu sexo? [ M / F ]: ");        String sexo = inputSexo.nextLine();        switch (sexo.toUpperCase()) {            case "F":                System.out.println("Você é mulher");                break;            case "M":                System.out.println("Você é homem");                break;        }    }}